        { id: "c25_s2_156", q: "What is 'Z' in the given set of reactions? (Anhy = Anhydrous, ethanolic = in ethanol) C₆H₅OCH₃ → (HI) → X + Y (C₆H₆ over Anhy. AlCl₃) → Z", options: ["C₂H₅-C₆H₄ (benzene ring with ethyl group)", "CH₂Cl-C₆H₄ (benzene ring with chloromethyl group)", "Cl-C₆H₄ (chlorobenzene)", "CH₃-C₆H₄ (toluene)"], ans: 3, topic: "Organic Chemistry - Friedel-Crafts Reaction", difficulty: "Hard" },
        { id: "c25_s2_157", q: "Which of the following reactions is an example of Clemmensen reduction?", options: ["R-C(=O)-Cl + H₂ → (Pd/BaSO₄) → R-C(=O)-H + HCl", "R-C(=O)-H → ((i)NH₂-NH₂/(ii)KOH|CH₂-CH₂|OH) → R-CH₃", "R-C(=O)-OC₂H₅ → (1.DIBAL-H/2.H₂O) → R-C(=O)-H + C₂H₅OH", "R-C(=O)-CH₃ → (Zn-Hg/HCl) → R-CH₂-CH₃"], ans: 3, topic: "Organic Chemistry - Reduction Reactions", difficulty: "Hard" },
        { id: "c25_s2_158", q: "Which of the following can undergo Hell-Volhard-Zelinsky reaction?", options: ["Benzene-carboxylic acid", "Phenylmethylacetic acid (with phenyl group on benzene ring and CH₂CO₂H)", "Benzaldehyde with CH₂CHO", "Phenylketone with CH₂-C(=O)-CH₃"], ans: 1, topic: "Organic Chemistry - Hell-Volhard-Zelinsky Reaction", difficulty: "Hard" },
        { id: "c25_s2_159", q: "Which of the following has lowest pK_a value?", options: ["Phenol with O-H and NO₂", "Benzoic acid", "Benzoic acid with OCH₃ at para position", "Benzoic acid with NO₂ at para position"], ans: 3, topic: "Organic Chemistry - Acidity", difficulty: "Hard" },
        { id: "c25_s2_160", q: "The correct statements about the products B and C in the given reactions are CH₃CH₂OH → (HCl/Anhy ZnCl₂) → A + Y", options: ["I & III", "II & III", "I, II & IV", "II, III & IV"], ans: 2, topic: "Organic Chemistry - Product Identification", difficulty: "Hard" }
